<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Models\HrCompetency; use App\Modules\Hr\Performance\Models\HrEmployeeCompetency; use App\Modules\Hr\Performance\Models\HrPerformanceCycle; use App\Modules\Hr\Personnel\Models\HrEmployee;
class AssessCompetencyAction { public function __construct(private HrAuditService $audit){} public function execute(HrEmployee $employee,HrCompetency $competency,?HrPerformanceCycle $cycle,int $current,int $target,?string $evidence=null):HrEmployeeCompetency{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.performance.evaluate'),403);abort_unless($employee->legal_entity_id===$tenant&&$competency->legal_entity_id===$tenant&&(!$cycle||$cycle->legal_entity_id===$tenant),404);abort_if($current<1||$current>5||$target<1||$target>5,422);$row=HrEmployeeCompetency::updateOrCreate(['employee_id'=>$employee->id,'competency_id'=>$competency->id,'cycle_id'=>$cycle?->id],['legal_entity_id'=>$tenant,'current_level'=>$current,'target_level'=>$target,'evidence'=>$evidence,'assessed_by'=>auth()->id()]);$this->audit->log('employee_competency_assessed',$row,null,['current_level'=>$current,'target_level'=>$target]);return $row;} }
